const shapes: { id: GlassShape; label: string; icon: React.ReactNode }[] = [
  { id: 'circles', label: 'Circles', icon: <CirclesIcon /> },
  { id: 'lines',   label: 'Lines',   icon: <LinesIcon /> },
  { id: 'wave',    label: 'Wave',    icon: <WaveIcon /> },
  { id: 'zigzag',  label: 'Zigzag',  icon: <ZigzagIcon /> },
];

interface ShapeSelectorProps {
  value: GlassShape;
  onChange: (value: GlassShape) => void;
}

export function ShapeSelector({ value, onChange }: ShapeSelectorProps) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement | null>(null);

  const selected = shapes.find((s) => s.id === value) ?? shapes[0];

  useEffect(() => {
    if (!open) return;
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, [open]);

  return (
    <div ref={ref} className={`selector${open ? ' open' : ''}`}>
      <button type="button" className="selector-trigger" onClick={() => setOpen((o) => !o)}>
        <span className="selector-left">
          <span className="option-icon">{selected.icon}</span>
          <span className="option-text">{selected.label}</span>
        </span>
        <img
          src={`${import.meta.env.BASE_URL}icons/chevron-down.svg`}
          className="chevron"
          alt=""
          style={{ filter: 'brightness(0) invert(78%)' }}
        />
      </button>
      <div className="dropdown">
        {shapes.map((shape) => (
          <button
            key={shape.id}
            type="button"
            className={`dropdown-item${shape.id === value ? ' active' : ''}`}
            onClick={() => { onChange(shape.id); setOpen(false); }}
          >
            <span className="option-icon">{shape.icon}</span>
            <span className="dropdown-item-text">{shape.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
